<style>
/* 所有样式前都加上 .my-foldable-block 容器限定 */
.my-foldable-block .thinking-description {
  background: transparent;
  border: none;
  box-shadow: none;
  color: #fff;
}

.my-foldable-block .thinking-summary {
  padding: 12px 16px;
  color: white;
  cursor: pointer;
  list-style: none;
  background: transparent;
  font-weight: 600;
  font-size: 2rem;           /* 调大字号 */
  letter-spacing: 0.5px;
  text-shadow: 0 2px 4px rgba(0, 0, 0, 0.5);
  border: none;
  transition: color 0.2s ease, text-shadow 0.2s ease;
  display: block;            /* 占满整行 */
  text-align: center;        /* 居中 */
}

.my-foldable-block .thinking-content {
  max-height: 300px;
  overflow-y: auto;
  padding: 8px 16px;
  background: transparent;
  color: #f0f8ff;
  line-height: 1.7;
  font-size: 1rem;
  text-shadow: 0 1px 3px rgba(0, 0, 0, 0.5);
  white-space: pre-wrap;
  border: none;
  font-family: 'SimSun', '宋体', serif;
}

/* 跳动动画 */
@keyframes bounce {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-6px); }
}

.my-foldable-block .jump-char {
  display: inline-block;
  animation: bounce 0.8s infinite ease-in-out;
  animation-delay: calc(0.1s * var(--i));
}

/* 滚动条样式 */
.my-foldable-block .thinking-description::-webkit-scrollbar {
  width: 6px;
}
.my-foldable-block .thinking-description::-webkit-scrollbar-track {
  background: transparent;
}
.my-foldable-block .thinking-description::-webkit-scrollbar-thumb {
  background: rgba(255, 255, 255, 0.5);
  border-radius: 6px;
}

.my-foldable-block .thinking-summary::marker {
  display: none;
}

/* 悬停高亮 */
.my-foldable-block .thinking-summary:hover .jump-char {
  color: #aaddff;
  text-shadow: 0 2px 8px rgba(0, 160, 255, 0.8);
}

/* 强制背景透明（仅限该容器内部） */
.my-foldable-block .thinking-description,
.my-foldable-block .thinking-description * {
  background: transparent !important;
  border-color: transparent !important;
  box-shadow: none !important;
  backdrop-filter: none !important;
}
